"use client";

import { usePathname } from "next/navigation";
import { Bell } from "lucide-react";
import { useCurrentUser } from "@/components/auth/AuthProvider";

const PATH_TITLES: Record<string, string> = {
  "/dashboard": "Dashboard",
  "/weekly/reflection": "Weekly Reflection",
  "/weekly/checkin": "Team Check-In",
  "/monthly/self-score": "Monthly Self-Score",
  "/monthly/score-team": "Score My Team",
  "/goals": "My Goals",
  "/tasks": "My Tasks",
  "/history": "My History",
  "/feedback": "My Feedback",
  "/team": "My Team",
  "/team/goals": "Team Goals",
  "/team/tasks": "Team Tasks",
  "/admin/employees": "Employees",
  "/admin/monitoring": "Review Monitor",
  "/admin/org-changes": "Org Changes",
  "/admin/increments": "Increment Processing",
  "/admin/reports": "Reports",
  "/admin/notifications": "Notifications",
  "/admin/config": "System Config",
  "/executive": "Executive Dashboard",
  "/executive/increments": "Approve Increments",
  "/executive/overrides": "Rating Overrides",
  "/welcome": "Welcome",
};

function getPageTitle(pathname: string): string {
  // Exact match
  if (PATH_TITLES[pathname]) return PATH_TITLES[pathname];
  // Prefix match (e.g. /admin/employees/EMP-001)
  for (const [prefix, title] of Object.entries(PATH_TITLES)) {
    if (pathname.startsWith(prefix + "/")) return title;
  }
  return "Crystal People";
}

const ROLE_PILL: Record<string, { label: string; color: string }> = {
  employee: { label: "Employee", color: "bg-blue-100 text-blue-800" },
  manager: { label: "Manager", color: "bg-teal-100 text-teal-800" },
  hr: { label: "HR", color: "bg-purple-100 text-purple-800" },
  md: { label: "MD / CEO", color: "bg-amber-100 text-amber-800" },
};

export function Header() {
  const pathname = usePathname();
  const { user } = useCurrentUser();
  const title = getPageTitle(pathname);
  const rolePill = user ? ROLE_PILL[user.role] : null;

  return (
    <header className="h-14 bg-white border-b border-gray-100 flex items-center justify-between px-6 flex-shrink-0">
      <h1 className="text-base font-semibold text-primary-900">{title}</h1>
      <div className="flex items-center gap-3">
        <button className="relative p-2 rounded-lg hover:bg-gray-50 text-gray-500 hover:text-gray-700 transition-colors">
          <Bell size={18} />
        </button>
        <div className="flex items-center gap-2">
          {rolePill && (
            <span className={`text-xs font-medium px-2 py-0.5 rounded-full ${rolePill.color}`}>
              {rolePill.label}
            </span>
          )}
          <div className="w-8 h-8 rounded-full bg-primary-900 flex items-center justify-center">
            <span className="text-white text-xs font-semibold">
              {user?.name?.charAt(0)?.toUpperCase() ?? "?"}
            </span>
          </div>
        </div>
      </div>
    </header>
  );
}
