"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { useState } from "react";
import {
  LayoutDashboard,
  ClipboardList,
  Target,
  CheckSquare,
  History,
  MessageSquare,
  Users,
  UserCheck,
  BarChart3,
  Settings,
  Building2,
  TrendingUp,
  Bell,
  ChevronLeft,
  ChevronRight,
  LogOut,
  Shield,
  Star,
} from "lucide-react";
import type { Role } from "@/lib/types";
import { cn } from "@/lib/utils";

interface NavItem {
  href: string;
  label: string;
  icon: React.ComponentType<{ size?: number; className?: string }>;
}

interface NavSection {
  section: string;
  roles: Role[];
  items: NavItem[];
}

const NAV: NavSection[] = [
  {
    section: "My Work",
    roles: ["employee", "manager", "hr", "md"],
    items: [
      { href: "/dashboard", label: "Dashboard", icon: LayoutDashboard },
      { href: "/weekly/reflection", label: "Weekly Reflection", icon: ClipboardList },
      { href: "/monthly/self-score", label: "Monthly Self-Score", icon: Star },
      { href: "/goals", label: "My Goals", icon: Target },
      { href: "/tasks", label: "My Tasks", icon: CheckSquare },
      { href: "/history", label: "My History", icon: History },
      { href: "/feedback", label: "My Feedback", icon: MessageSquare },
    ],
  },
  {
    section: "My Team",
    roles: ["manager", "hr", "md"],
    items: [
      { href: "/team", label: "Team Overview", icon: Users },
      { href: "/weekly/checkin", label: "Weekly Check-In", icon: UserCheck },
      { href: "/monthly/score-team", label: "Score My Team", icon: BarChart3 },
      { href: "/team/goals", label: "Team Goals", icon: Target },
      { href: "/team/tasks", label: "Team Tasks", icon: CheckSquare },
    ],
  },
  {
    section: "HR Admin",
    roles: ["hr", "md"],
    items: [
      { href: "/admin/employees", label: "Employees", icon: Users },
      { href: "/admin/monitoring", label: "Review Monitor", icon: Shield },
      { href: "/admin/org-changes", label: "Org Changes", icon: Building2 },
      { href: "/admin/increments", label: "Increments", icon: TrendingUp },
      { href: "/admin/reports", label: "Reports", icon: BarChart3 },
      { href: "/admin/notifications", label: "Notifications", icon: Bell },
      { href: "/admin/config", label: "Config", icon: Settings },
    ],
  },
  {
    section: "Executive",
    roles: ["md"],
    items: [
      { href: "/executive", label: "Exec Dashboard", icon: LayoutDashboard },
      { href: "/executive/increments", label: "Approve Increments", icon: TrendingUp },
      { href: "/executive/overrides", label: "Rating Overrides", icon: Shield },
    ],
  },
];

interface SidebarProps {
  role: Role;
  userName: string;
  onSignOut: () => void;
}

export function Sidebar({ role, userName, onSignOut }: SidebarProps) {
  const pathname = usePathname();
  const [collapsed, setCollapsed] = useState(false);

  const visibleSections = NAV.filter((s) => s.roles.includes(role));

  // For manager role: hide goal/task pages that are employee-only concepts
  // (managers DO have their own goals if they are also white_collar, so keep them)

  return (
    <aside
      className={cn(
        "flex flex-col h-screen sticky top-0 transition-all duration-200 custom-scrollbar overflow-y-auto",
        "bg-primary-900 border-r border-primary-800",
        collapsed ? "w-16" : "w-60"
      )}
    >
      {/* Logo */}
      <div className={cn(
        "flex items-center gap-3 px-4 py-5 border-b border-primary-800",
        collapsed && "justify-center px-3"
      )}>
        <div className="w-8 h-8 rounded-lg bg-accent-500 flex items-center justify-center flex-shrink-0">
          <span className="text-white font-bold text-sm">CP</span>
        </div>
        {!collapsed && (
          <div>
            <p className="text-white font-semibold text-sm leading-tight">Crystal People</p>
            <p className="text-primary-400 text-xs">Performance Platform</p>
          </div>
        )}
      </div>

      {/* Nav */}
      <nav className="flex-1 px-2 py-4 space-y-5">
        {visibleSections.map((section) => (
          <div key={section.section}>
            {!collapsed && (
              <p className="sidebar-section-label">{section.section}</p>
            )}
            <ul className="space-y-0.5">
              {section.items.map((item) => {
                const Icon = item.icon;
                const isActive =
                  pathname === item.href ||
                  (item.href !== "/dashboard" && pathname.startsWith(item.href));

                return (
                  <li key={item.href}>
                    <Link
                      href={item.href}
                      className={cn("sidebar-item", isActive && "active", collapsed && "justify-center px-2")}
                      title={collapsed ? item.label : undefined}
                    >
                      <Icon size={17} className="flex-shrink-0" />
                      {!collapsed && <span>{item.label}</span>}
                    </Link>
                  </li>
                );
              })}
            </ul>
          </div>
        ))}
      </nav>

      {/* Footer */}
      <div className="border-t border-primary-800 p-3 space-y-1">
        <button
          onClick={() => setCollapsed(!collapsed)}
          className="sidebar-item w-full text-left"
          title={collapsed ? "Expand sidebar" : "Collapse sidebar"}
        >
          {collapsed ? <ChevronRight size={17} /> : (
            <>
              <ChevronLeft size={17} />
              <span>Collapse</span>
            </>
          )}
        </button>
        {!collapsed && (
          <div className="px-3 py-2">
            <p className="text-white text-sm font-medium truncate">{userName}</p>
            <p className="text-primary-400 text-xs capitalize">{role}</p>
          </div>
        )}
        <button
          onClick={onSignOut}
          className="sidebar-item w-full text-left text-red-400 hover:text-red-300 hover:bg-red-900/20"
          title="Sign out"
        >
          <LogOut size={17} className="flex-shrink-0" />
          {!collapsed && <span>Sign out</span>}
        </button>
      </div>
    </aside>
  );
}
